import argparse
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_configs=None):
    new_topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=topic_configs)
    admin_client.create_topics([new_topic])

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-server', required=True, help='Bootstrap server address')
    parser.add_argument('--topic-name', required=True, help='Name of the topic to create')
    parser.add_argument('--num-partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--topic-configs', nargs='+', help='Topic configurations in key=value format')

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_server)

    if args.topic_configs:
        topic_configs = {k: v for k, v in (config.split('=') for config in args.topic_configs)}
    else:
        topic_configs = None

    create_topic(admin_client, args.topic_name, args.num_partitions, args.replication_factor, topic_configs)

if __name__ == '__main__':
    main()